const raw = $input.first().json;
let payload;
if (raw.body?.body && typeof raw.body.body === 'object') {
  payload = raw.body.body;
} else if (raw.body && typeof raw.body === 'object') {
  payload = raw.body;
} else {
  payload = raw;
}
return {
  json: {
    managerEmail: payload.managerEmail || '',
    costUrl: payload.costUrl || '',
    contactName: payload.contactName || '',
    company: payload.company || '',
    reportId: payload.reportId || '',
    timestamp: payload.timestamp || new Date().toISOString()
  }
};

const d = $input.first().json;
const managerEmail = d.managerEmail || '';
const costUrl = d.costUrl || '';
const contactName = d.contactName || '';
const company = d.company || '';

var emailHtml = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<h1 style="margin: 0; font-size: 24px;">Cost & Automation Analysis</h1>' +
    '<p style="margin: 8px 0 0; opacity: 0.8;">' + (company ? company + ' — ' : '') + 'Shared with you</p>' +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">Hi there,</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;">' + (contactName ? '<strong>' + contactName + '</strong> has' : 'Someone has') + ' shared a cost and automation analysis' + (company ? ' for <strong>' + company + '</strong>' : '') + ' with you.</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;">This report shows the current cost of manual processes, estimated time savings, and the projected return on investment from automation.</p>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + costUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">View Cost Analysis</a>' +
    '</div>' +
    '<hr style="border: none; border-top: 1px solid #e2e8f0; margin: 24px 0;">' +
    '<p style="font-size: 12px; color: #94a3b8; text-align: center;">This analysis was generated by Sharpin. If you have any questions, reply to this email.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: String(managerEmail || ''),
    subject: (contactName ? contactName + ' shared' : 'Shared') + ' a Cost & Automation Analysis' + (company ? ' — ' + company : ''),
    html: emailHtml
  }
};
